function gnomeSort(arr) {
	let n = arr.length;
	let index = 0;
	while (index < n) {
		if (index === 0) index++;
		if (arr[index] >= arr[index - 1]) {
			index++;
		} else {
			[arr[index], arr[index - 1]] = [arr[index - 1], arr[index]];
			index--;
		}
	}
	return arr;
}

