public static void gnomeSort(int[] arr) {
	int n = arr.length;
	int index = 0;
	while (index < n) {
		if (index == 0) index++;
		if (arr[index] >= arr[index - 1]) {
			index++;
		} else {
			int temp = arr[index];
			arr[index] = arr[index - 1];
			arr[index - 1] = temp;
			index--;
		}
	}
}

